#!/usr/bin/env node
// Extracts {variable_name → question_text} from the local data
// dictionary CSV (docs/data-dictionary.csv) into a small JSON file
// served from public/data/question-texts.json. Lets the UI display
// the verbatim survey question above each chart without bloating
// meta.json (which is regenerated by Matt's R precompute pipeline).
//
// Run: node scripts/build-question-texts.mjs
// Output: public/data/question-texts.json

import fs from 'node:fs';
import path from 'node:path';

const SOURCE = path.resolve('docs/data-dictionary.csv');
const TARGET = path.resolve('public/data/question-texts.json');

function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  let i = 0;
  while (i < text.length) {
    const c = text[i];
    if (inQuotes) {
      if (c === '"' && text[i + 1] === '"') {
        field += '"';
        i += 2;
        continue;
      }
      if (c === '"') {
        inQuotes = false;
        i++;
        continue;
      }
      field += c;
      i++;
      continue;
    }
    if (c === '"') {
      inQuotes = true;
      i++;
      continue;
    }
    if (c === ',') {
      row.push(field);
      field = '';
      i++;
      continue;
    }
    if (c === '\n') {
      row.push(field);
      rows.push(row);
      row = [];
      field = '';
      i++;
      continue;
    }
    if (c === '\r') {
      i++;
      continue;
    }
    field += c;
    i++;
  }
  if (field.length || row.length) {
    row.push(field);
    rows.push(row);
  }
  return rows;
}

const text = fs.readFileSync(SOURCE, 'utf8');
const rows = parseCsv(text);
const header = rows[0];
const idxVar = header.indexOf('variable_name');
const idxQ = header.indexOf('question_text');
const idxConstruct = header.indexOf('construct');
const idxClean = header.indexOf('clean_variable_name');
const idxPI = header.indexOf('is_platform_indexed');

if (idxVar < 0 || idxQ < 0) {
  console.error('Expected variable_name and question_text columns');
  process.exit(1);
}

const out = {};
let count = 0;
for (const row of rows.slice(1)) {
  const name = row[idxVar];
  if (!name) continue;
  const question = (row[idxQ] || '').trim();
  if (!question) continue;
  out[name] = {
    question_text: question,
    construct: row[idxConstruct] || null,
    clean_variable_name: row[idxClean] || null,
    is_platform_indexed:
      (row[idxPI] || '').toUpperCase() === 'TRUE',
  };
  count++;
}

fs.mkdirSync(path.dirname(TARGET), { recursive: true });
fs.writeFileSync(
  TARGET,
  JSON.stringify(
    { generated_at: new Date().toISOString(), variables: out },
    null,
    2,
  ),
);
console.log(`Wrote ${count} entries to ${TARGET}`);
